import { useState } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import Leaderboard from "./components/Leaderboard";
import AddEntry from "./components/AddEntry";
import RemoveEntry from "./components/RemoveEntry";
import StatsPanel from "./components/StatsPanel";
import PerformancePanel from "./components/PerformancePanel";
import HistoryPanel from "./components/HistoryPanel";

const queryClient = new QueryClient();

export default function App() {
  const [activeTab, setActiveTab] = useState("leaderboard");

  const tabs = [
    { id: "leaderboard", label: "🏆 Leaderboard" },
    { id: "add", label: "➕ Add" },
    { id: "remove", label: "🗑️ Remove" },
    { id: "stats", label: "📊 Stats" },
    { id: "performance", label: "⚡ Performance" },
    { id: "history", label: "📜 History" },
  ];

  return (
    <QueryClientProvider client={queryClient}>
      <div className="min-h-screen bg-gray-950 text-white">
        {/* Header */}
        <div className="bg-gray-900 border-b border-gray-800 px-6 py-4">
          <h1 className="text-3xl font-bold text-center bg-gradient-to-r from-yellow-400 via-orange-400 to-red-500 bg-clip-text text-transparent">
            🏆 Dynamic Leaderboard System
          </h1>
          <p className="text-center text-gray-400 text-sm mt-1">
            Real-time rankings • Live stats • Score velocity tracking
          </p>
        </div>

        {/* Tabs */}
        <div className="flex justify-center gap-2 mt-6 px-4 flex-wrap">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 ${
                activeTab === tab.id
                  ? "bg-yellow-500 text-gray-900 shadow-lg shadow-yellow-500/30"
                  : "bg-gray-800 text-gray-400 hover:bg-gray-700"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="max-w-4xl mx-auto px-4 py-8">
          {activeTab === "leaderboard" && <Leaderboard />}
          {activeTab === "add" && <AddEntry />}
          {activeTab === "remove" && <RemoveEntry />}
          {activeTab === "stats" && <StatsPanel />}
          {activeTab === "performance" && <PerformancePanel />}
          {activeTab === "history" && <HistoryPanel />}
        </div>
      </div>
    </QueryClientProvider>
  );
}
